        if (!node.isArray()) return null;
        List<KeyAlgorithm> list = new ArrayList<>();
        for (JsonNode n : node) {
            KeyAlgorithm alg = KeyAlgorithm.fromAwsName(n.asText());
            if (alg != null) {
                list.add(alg);
            }
        }
        return list.isEmpty() ? null : list;
    }
